#!/usr/bin/env python3
# -*- coding: utf-8 -*-


def main():
    n = int(input())
    a = map(int, input().split())
    m = 0
    c = 0
    for x in a:
        x2 = 0
        while x % 2 == 0:
            x2 += 1
            x //= 2
        if x2 > m:
            m = x2
            c = 1
        elif x2 == m:
            c += 1
    print(2**m, c)


if __name__ == '__main__':
    main()
